// Patches build/wasm_exec.js generated by workers-assets-gen (tinygo mode) to add
// the runtime.getRandomData import required by tinygo v0.41.1+.
// See: https://github.com/tinygo-org/tinygo/issues/5357
import { readFileSync, writeFileSync } from "node:fs";

const file = "./build/wasm_exec.js";
const src = readFileSync(file, "utf8");

if (src.includes('"runtime.getRandomData"')) {
  process.exit(0); // already present, nothing to do
}

const anchor = '// func sleepTicks(timeout int64)';
if (!src.includes(anchor)) {
  console.error(`patch-wasm-exec: anchor not found in ${file}`);
  process.exit(1);
}

const patch = `// func getRandomData(r []byte)
					"runtime.getRandomData": (slice_ptr, slice_len, slice_cap) => {
						crypto.getRandomValues(loadSlice(slice_ptr, slice_len, slice_cap));
					},

					${anchor}`;

writeFileSync(file, src.replace(anchor, patch));
console.log("patch-wasm-exec: added runtime.getRandomData");
